  "tests": [
    {
      "name": "valid_jwt_token",
      "input": {
        "token": "valid.jwt.token",
        "authSecret": "test_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": true,
        "user": {
          "id": "user123",
          "roles": ["admin"]
        }
      },
      "notes": "Tests valid JWT token verification with correct secret and issuer."
    },
    {
      "name": "invalid_jwt_token",
      "input": {
        "token": "invalid.jwt.token",
        "authSecret": "test_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": false,
        "error": "Invalid token"
      },
      "notes": "Tests handling of an invalid JWT token."
    },
    {
      "name": "expired_jwt_token",
      "input": {
        "token": "expired.jwt.token",
        "authSecret": "test_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": false,
        "error": "Token expired"
      },
      "notes": "Tests handling of an expired JWT token."
    },
    {
      "name": "missing_auth_secret",
      "input": {
        "token": "valid.jwt.token",
