      },
      "output": {
        "isValid": false,
        "error": "Missing auth secret"
      },
      "notes": "Tests behavior when AUTH_SECRET is not provided."
    },
    {
      "name": "invalid_issuer",
      "input": {
        "token": "valid.jwt.token",
        "authSecret": "test_secret",
        "validIssuers": ["https://invalidissuer.com"]
      },
      "output": {
        "isValid": false,
        "error": "Invalid issuer"
      },
      "notes": "Tests handling of a valid token with an invalid issuer."
    },
    {
      "name": "valid_m2m_token",
      "input": {
        "token": "valid.m2m.token",
        "authSecret": "test_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": true,
        "user": {
          "id": "m2m_user",
          "roles": ["m2m"]
        }
      },
      "notes": "Tests valid M2M token verification."
    },
    {
      "name": "role_scope_validation",
      "input": {
        "token": "valid.jwt.token.with.scope",
        "authSecret": "test_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": true,
        "roles": ["admin"],
        "scopes": ["read", "write"]
      },
      "notes": "Tests role and scope validation from a valid token."
